sp_header_footer.css:
/* USER AVATAR */
.avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #2563eb;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 600;
}

.profile-card {


    padding: 12px;
    display: flex;
    align-items: center;
    gap: 14px;
    width: 100%;
    max-width: 560px;
    border: 1px solid rgba(255,255,255,0.08);

}



.profile-info h2{
    margin: 0;    
    font-size: 36px;
    font-weight: 100;
}



/* HEADER */

.sim-header {
  width: 100%;
  background: #fff;
  border-bottom: 1px solid #e5e7eb;
  position: sticky;
  top: 0;
  z-index: 100;
}

/* CONTAINER */
.sim-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
  padding: 0 24px;
  flex-wrap: nowrap;
}

/* LEFT GROUP */
.sim-left {
  display: flex;
  align-items: center;
  gap: 20px;
  flex: 1;
  min-width: 0;
}

/* LOGO */
.sim-logo {
  display: flex;
  align-items: center;
}

.logo-link {
  display: flex;
  align-items: center;
}

.logo-img {
  height: 34px;
  width: auto;
}

/* NAVIGATION */
.sim-nav {
  display: flex;
  align-items: center;
  gap: 8px;
  white-space: nowrap;
}

.sim-nav a {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  border-radius: 8px;
  text-decoration: none;
  color: #374151 !important;
  font-size: 13px;
  font-weight: 500;
  transition: all 0.2s ease;
}

/* HOVER EFFECT */
.sim-nav a:hover {
  background: #f3f4f6;
  color: #111827 !important;
}

/* ACTIVE MENU ITEM (DYNAMIC HIGHLIGHT) */
.sim-nav a.active {
  background: #e8f0ff !important;
  color: #2563eb !important;
  border-radius: 8px;
  font-weight: 600 !important;
  padding: 8px 14px;
}

/* RIGHT SIDE */
.sim-right {
  display: flex;
  align-items: center;
  gap: 12px;
  white-space: nowrap;
}

/* PERIOD BUTTON */
.period-btn {
  border: 1px solid #d1d5db;
  padding: 5px 10px;
  background: #fff;
  border-radius: 6px;
  font-size: 12px;
  cursor: pointer;
}

/* NAVBAR RIGHT FIX */
.navbar-right {
  display: flex !important;
  align-items: center;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none;
}

.navbar-right > li {
  float: none !important;
  display: flex;
  align-items: center;
}



/* DROPDOWN */
.dropdown {
  position: relative;
}

.dropdown-menu {
  position: absolute;
  top: 110%;
  right: 0;
  z-index: 9999;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  min-width: 150px;
  box-shadow: 0 8px 20px rgba(0,0,0,0.08);
}

.dropdown-menu li a {
  padding: 10px 14px;
  display: block;
  color: #374151 !important;
  text-decoration: none;
}

.dropdown-menu li a:hover {
  background: #f9fafb;
}

/* FINAL FORCE */
.sim-header * {
  white-space: nowrap;
}

sp_header_footer.script:
(function() {

	data.user = {
		sys_id: gs.getUserID(),
		name: gs.getUserDisplayName(),
		logged_in: gs.getUserID() ? true : false
	};

	data.avatarProfile = {
		userID: data.user.sys_id,
		name: data.user.name

	};

	data.isIncentNowGroupAdmin= gs.hasRole('x_ctans_incentnow.business_group_admin') || gs.hasRole('x_ctans_incentnow.admin');


	var allowedReportRoles = [
		'x_ctans_incentnow.business_group_admin',
    'x_ctans_incentnow.admin',

    'x_ctans_incentnow.business_group_executive',
    'x_ctans_incentnow.manager',
    'x_ctans_incentnow.org_executive'
];

data.canViewReports = false;

for (var i = 0; i < allowedReportRoles.length; i++) {

    if (gs.hasRole(allowedReportRoles[i])) {
		//gs.addInfoMessage(allowedReportRoles[i]);
        data.canViewReports = true;
        break;
    }

}


	data.initials = gs.getUser().getFirstName().charAt(0) + gs.getUser().getLastName().charAt(0);

	data.logoutUrl = "/logout.do";

})();
